import React, { useState } from 'react';

interface EmailPopupProps {
  onClose: () => void;
}

const EmailPopup: React.FC<EmailPopupProps> = ({ onClose }) => {
  const [email, setEmail] = useState('');
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (email) {
      setSubmitted(true);
      setTimeout(onClose, 2000);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
      <div className="bg-zinc-900 border-4 border-white rounded-[3rem] p-8 md:p-12 max-w-lg w-full relative shadow-[20px_20px_0px_0px_rgba(255,255,255,0.1)]">
        <button 
          onClick={onClose}
          className="absolute top-6 right-6 text-white/50 hover:text-white"
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>

        {!submitted ? (
          <div className="text-center">
            <div className="bg-yellow-400 text-black inline-block px-4 py-1 rounded-full text-xs font-black mb-4 uppercase tracking-widest">
              Join the underground
            </div>
            <h2 className="text-3xl md:text-4xl font-black mb-4 tracking-tighter leading-none">
              NEVER MISS A RELEASE.
            </h2>
            <p className="text-white/60 mb-8 text-sm md:text-base leading-relaxed">
              Get exclusive demos, tour announcements, and limited vinyl drops delivered straight to your inbox.
            </p>
            <form onSubmit={handleSubmit} className="space-y-4">
              <input
                type="email"
                placeholder="YOUR EMAIL ADDR..."
                required
                className="w-full bg-black border-2 border-white/20 rounded-full px-6 py-4 text-white focus:outline-none focus:border-yellow-400 transition-all text-center uppercase font-bold text-sm tracking-widest"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
              <button
                type="submit"
                className="w-full bg-white text-black font-black py-4 rounded-full hover:bg-yellow-400 transition-colors transform hover:scale-105 active:scale-95 text-lg"
              >
                SUBSCRIBE
              </button>
            </form>
          </div>
        ) : (
          <div className="text-center py-12">
            <h2 className="text-4xl font-black mb-4 text-yellow-400">THANK YOU.</h2>
            <p className="text-white/60">YOU ARE NOW IN THE SYSTEM.</p>
          </div>
        )}
      </div>
    </div>
  );
};

