interface EmailPopupProps {
  onClose: () => void;
}

const EmailPopup: React.FC<EmailPopupProps> = ({ onClose }) => {
  const [email, setEmail] = useState('');
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (email) {
      setSubmitted(true);
      setTimeout(onClose, 2500);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
      <div className="bg-zinc-950 border-4 border-white rounded-[4rem] p-10 md:p-14 max-w-xl w-full relative shadow-2xl">
        <button 
          onClick={onClose}
          className="absolute top-8 right-8 text-white/30 hover:text-white transition-colors"
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>

        {!submitted ? (
          <div className="text-center space-y-6">
            <div className="bg-brand-plum text-black inline-block px-5 py-1 rounded-full text-[10px] font-bold mb-4 uppercase tracking-[0.2em]">
              The Soulful Crowd//
            </div>
            <h2 className="text-4xl md:text-5xl font-bold mb-4 tracking-tighter leading-tight uppercase">
              Stay in the<br/><span className="text-brand-straw">Flow//</span>
            </h2>
            <p className="text-white/40 mb-10 text-base leading-relaxed font-light">
              Join our mission to a global scale. Get notified about clean lo-fi drops and nostalgic anime aesthetic vinyl releases.
            </p>
            <form onSubmit={handleSubmit} className="space-y-4">
              <input
                type="email"
                placeholder="Your eMail..."
                required
                className="w-full bg-black border-2 border-white/10 rounded-full px-8 py-5 text-white focus:outline-none focus:border-brand-blue transition-all text-center uppercase font-bold text-sm tracking-widest placeholder:text-white/10"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
              <button
                type="submit"
                className="w-full bg-brand-blue text-black font-bold py-5 rounded-pill hover:bg-brand-straw transition-all transform hover:scale-105 text-lg shadow-lg shadow-brand-blue/10"
              >
                JOIN THE LIST//
              </button>
            </form>
          </div>
        ) : (
          <div className="text-center py-16 animate-pulse">
            <h2 className="text-5xl font-bold mb-4 text-brand-olivine uppercase tracking-tighter italic">VIBING//</h2>
            <p className="text-white/40 font-bold uppercase tracking-widest text-xs">YOU ARE NOW SYNCED WITH THE SOUL.</p>
          </div>
        )}
      </div>
    </div>
  );
};

