import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";

interface GeneratedImageProps {
  prompt: string;
  alt: string;
  className?: string;
  aspectRatio?: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
}

const GeneratedImage: React.FC<GeneratedImageProps> = ({ 
  prompt, 
  alt, 
  className = "", 
  aspectRatio = "1:1" 
}) => {
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // If no API key is set in environment, we skip generation
    if (!process.env.API_KEY || process.env.API_KEY === 'undefined') {
      setLoading(false);
      return;
    }

    const generateImage = async () => {
      try {
        setLoading(true);
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [
              {
                text: `90s retro anime style, high quality cel shaded, flat colors, clean lines, vintage cartoon aesthetic, centered character on solid dark background: ${prompt}`,
              },
            ],
          },
          config: {
            imageConfig: {
              aspectRatio: aspectRatio,
            },
          },
        });

        let foundUrl = null;
        if (response.candidates?.[0]?.content?.parts) {
          for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
              foundUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
              break;
            }
          }
        }

        if (foundUrl) {
          setImageUrl(foundUrl);
        }
      } catch (err) {
        console.error("Image generation skipped or failed:", err);
      } finally {
        setLoading(false);
      }
    };

    generateImage();
  }, [prompt, aspectRatio]);

  if (loading) {
    return (
      <div className={`bg-zinc-900 animate-pulse flex items-center justify-center ${className} border border-white/5 rounded-3xl`}>
      </div>
    );
  }

  // Graceful fallback if no AI image is generated
  if (!imageUrl) {
    return (
      <div className={`bg-zinc-900 flex flex-col items-center justify-center ${className} border-2 border-dashed border-white/5 rounded-3xl group overflow-hidden`}>
        <div className="text-white/10 font-bold text-[10px] uppercase tracking-[0.5em] mb-2 group-hover:text-brand-blue transition-colors">LIFE ROW//</div>
        <div className="w-8 h-1 bg-white/5 group-hover:bg-brand-straw transition-colors"></div>
      </div>
    );
  }

  return (
    <div className={`relative overflow-hidden group ${className}`}>
      <img 
        src={imageUrl} 
        alt={alt} 
        className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-700 image-reveal group-hover:scale-110"
      />
      <div className="absolute inset-0 bg-brand-blue/10 mix-blend-overlay opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
    </div>
  );
};

export default GeneratedImage;

import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";

interface GeneratedImageProps {
  prompt: string;
  alt: string;
  className?: string;
  aspectRatio?: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
  src?: string; // Optional direct source to bypass AI
}

const GeneratedImage: React.FC<GeneratedImageProps> = ({ 
  prompt, 
  alt, 
  className = "", 
  aspectRatio = "1:1",
  src
}) => {
  const [imageUrl, setImageUrl] = useState<string | null>(src || null);
  const [loading, setLoading] = useState(!src);

  useEffect(() => {
    // If we have a direct source or no API key, don't attempt AI generation
    if (src || !process.env.API_KEY || process.env.API_KEY === 'undefined' || process.env.API_KEY === '') {
      setLoading(false);
      return;
    }

    const generateImage = async () => {
      try {
        setLoading(true);
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [
              {
                text: `90s retro anime style, high quality cel shaded, vintage cartoon aesthetic, clean lines, flat colors, centered character on dark background: ${prompt}`,
              },
            ],
          },
          config: {
            imageConfig: {
              aspectRatio: aspectRatio,
            },
          },
        });

        let foundUrl = null;
        if (response.candidates?.[0]?.content?.parts) {
          for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
              foundUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
              break;
            }
          }
        }

        if (foundUrl) {
          setImageUrl(foundUrl);
        }
      } catch (err: any) {
        // Specifically handle quota errors (429) silently
        if (err?.message?.includes('429') || err?.message?.includes('quota')) {
          console.warn("AI Quota exhausted. Showing placeholder.");
        } else {
          console.error("Image generation error:", err);
        }
        // Fallback to null so placeholder shows
        setImageUrl(null);
      } finally {
        setLoading(false);
      }
    };

    generateImage();
  }, [prompt, aspectRatio, src]);

  if (loading) {
    return (
      <div className={`bg-zinc-900 animate-pulse flex items-center justify-center ${className} border border-white/5`}>
        <div className="w-8 h-8 border-2 border-white/10 border-t-brand-blue rounded-full animate-spin"></div>
      </div>
    );
  }

  // Graceful fallback if no image is available
  if (!imageUrl) {
    return (
      <div className={`bg-zinc-900 flex flex-col items-center justify-center ${className} border-2 border-dashed border-white/5 group overflow-hidden`}>
        <div className="text-white/10 font-bold text-[10px] uppercase tracking-[0.4em] mb-2 group-hover:text-brand-blue transition-colors">LIFE ROW//</div>
        <div className="w-12 h-0.5 bg-white/5 group-hover:bg-brand-straw transition-colors"></div>
      </div>
    );
  }

  return (
    <div className={`relative overflow-hidden group ${className}`}>
      <img 
        src={imageUrl} 
        alt={alt} 
        className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-700 image-reveal group-hover:scale-110"
      />
      <div className="absolute inset-0 bg-brand-blue/5 mix-blend-overlay opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
    </div>
  );
};

