    checkKey();
  }, []);

  useEffect(() => {
    if (isApiKeySelected) {
      const hasSeenPopup = localStorage.getItem('hasSeenPopup');
      if (!hasSeenPopup) {
        const timer = setTimeout(() => {
          setShowPopup(true);
        }, 2500);
        return () => clearTimeout(timer);
      }
