import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";

interface GeneratedImageProps {
  prompt: string;
  alt: string;
  className?: string;
  aspectRatio?: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
}

const GeneratedImage: React.FC<GeneratedImageProps> = ({ 
  prompt, 
  alt, 
  className = "", 
  aspectRatio = "1:1" 
}) => {
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);
  const retryCount = useRef(0);
  const maxRetries = 3;

  const generateImage = async () => {
    try {
      setLoading(true);
      setError(false);

      // Create fresh instance to ensure we use the latest API key from the selection gate
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [
            {
              text: `90s retro anime style, high quality cel shaded, lo-fi aesthetic, cinematic lighting, ${prompt}`,
            },
          ],
        },
        config: {
          imageConfig: {
            aspectRatio: aspectRatio,
            imageSize: "1K"
          },
        },
      });

      if (!response.candidates?.[0]?.content?.parts) {
        throw new Error("Invalid response format");
      }

      let foundUrl = null;
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          foundUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
          break;
        }
      }

      if (foundUrl) {
        setImageUrl(foundUrl);
        retryCount.current = 0;
      } else {
        throw new Error("No image data found");
      }
    } catch (err: any) {
      console.error("Image generation failed:", err);

      // Handle rate limiting (429) with exponential backoff
      const isRateLimit = err.message?.includes("429") || (err.status === 429);

      if (isRateLimit && retryCount.current < maxRetries) {
        retryCount.current += 1;
        const delay = Math.pow(2, retryCount.current) * 1000;
        console.log(`Retrying in ${delay}ms... (Attempt ${retryCount.current})`);
        setTimeout(generateImage, delay);
      } else {
        setError(true);
        setLoading(false);
      }
    } finally {
      if (!error) setLoading(false);
    }
  };

  useEffect(() => {
    generateImage();
  }, [prompt, aspectRatio]);

  if (loading) {
    return (
      <div className={`flex items-center justify-center bg-zinc-900 animate-pulse ${className}`}>
        <div className="w-8 h-8 border-4 border-brand-blue border-t-transparent rounded-full animate-spin"></div>
      </div>
    );
  }

  if (error || !imageUrl) {
    return (
      <div className={`flex flex-col items-center justify-center bg-zinc-950 border-2 border-white/5 p-4 text-center ${className}`}>
        <span className="text-white/10 font-bold text-xs uppercase tracking-widest mb-2">Signal Lost//</span>
        <button 
          onClick={() => { retryCount.current = 0; generateImage(); }}
          className="text-[10px] font-bold text-brand-blue hover:text-brand-straw uppercase tracking-widest"
        >
          Reconnect//
        </button>
      </div>
    );
  }

  return (
    <div className={`relative overflow-hidden group ${className}`}>
      <img 
        src={imageUrl} 
        alt={alt} 
        className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-700 image-reveal group-hover:scale-105"
      />
    </div>
  );
};

export default GeneratedImage;

import React, { useState } from 'react';
import { GoogleGenAI } from "@google/genai";

interface AssetCardProps {
  name: string;
  filename: string;
  prompt: string;
}

const AssetCard: React.FC<AssetCardProps> = ({ name, filename, prompt }) => {
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [generating, setGenerating] = useState(false);

  const generate = async () => {
    try {
      setGenerating(true);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [
            {
              text: `90s retro anime style, high quality cel shaded, flat colors, clean lines, vintage cartoon aesthetic, ${prompt}, centered character on solid dark background, studio portrait`,
            },
          ],
        },
        config: {
          imageConfig: {
            aspectRatio: "1:1",
            imageSize: "1K"
          },
        },
      });

      if (!response.candidates?.[0]?.content?.parts) throw new Error("No data");

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          const url = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
          setImageUrl(url);
          break;
        }
      }
    } catch (err: any) {
      console.error("Failed to generate asset:", err);
    } finally {
      setGenerating(false);
    }
  };

  const download = () => {
    if (!imageUrl) return;
    const link = document.createElement('a');
    link.href = imageUrl;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="bg-zinc-900/50 p-8 rounded-[3rem] border border-white/5 space-y-6">
      <div className="aspect-square bg-black rounded-3xl overflow-hidden border-2 border-white/5 relative">
        {imageUrl ? (
          <img src={imageUrl} alt={name} className="w-full h-full object-cover" />
        ) : (
          <div className="w-full h-full flex items-center justify-center">
            <span className="text-white/10 font-bold text-xs uppercase tracking-widest">No Signal//</span>
          </div>
        )}
        {generating && (
          <div className="absolute inset-0 bg-black/80 flex items-center justify-center">
            <div className="w-8 h-8 border-4 border-brand-blue border-t-transparent rounded-full animate-spin"></div>
          </div>
        )}
      </div>

      <div className="space-y-4">
        <div>
          <h3 className="text-xl font-bold uppercase tracking-tight">{name}</h3>
          <p className="text-[10px] text-white/30 font-bold uppercase tracking-widest">Target: {filename}</p>
        </div>

        <div className="flex gap-2">
          {!imageUrl ? (
            <button 
              onClick={generate}
              disabled={generating}
              className="flex-grow bg-white text-black font-bold py-3 rounded-full text-xs uppercase hover:bg-brand-straw transition-colors disabled:opacity-50"
            >
              {generating ? 'Transmitting...' : 'Generate Hi-Res//'}
            </button>
          ) : (
            <>
              <button 
                onClick={generate}
                disabled={generating}
                className="bg-zinc-800 text-white font-bold px-4 py-3 rounded-full text-[10px] uppercase hover:bg-zinc-700 transition-colors"
              >
                Regen//
              </button>
              <button 
                onClick={download}
                className="flex-grow bg-brand-blue text-black font-bold py-3 rounded-full text-xs uppercase hover:scale-105 transition-all"
              >
                Download File//
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

