import React, { useState } from 'react';

const FORMSPREE_ID = "maqyqobv";

interface EmailPopupProps {
  onClose: () => void;
}

const EmailPopup: React.FC<EmailPopupProps> = ({ onClose }) => {
  const [email, setEmail] = useState("");
  const [status, setStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus('submitting');

    try {
      const response = await fetch(`https://formspree.io/f/${FORMSPREE_ID}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      });

      if (response.ok) {
        setStatus('success');
      } else {
        setStatus('error');
      }
    } catch (err) {
      setStatus('error');
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/95 backdrop-blur-xl">
      <div className="bg-zinc-950 border-4 border-white rounded-[4rem] p-10 md:p-14 max-w-xl w-full relative shadow-[0_0_100px_rgba(255,255,255,0.1)] transition-all animate-in fade-in zoom-in duration-300">

        {/* High-Visibility Exit Button */}
        <button 
          onClick={onClose}
          className="absolute -top-4 -right-4 md:-top-6 md:-right-6 bg-white text-black p-4 rounded-full shadow-2xl hover:scale-110 active:scale-90 transition-all z-10 flex items-center gap-2 group"
          aria-label="Close"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"></path>
          </svg>
          <span className="hidden group-hover:block pr-2 text-[10px] font-bold tracking-widest">EXIT//</span>
        </button>

        <div className="text-center space-y-6">
          {status === 'success' ? (
            <div className="py-12 space-y-6 animate-in fade-in zoom-in duration-500">
              <div className="text-brand-straw text-6xl">✨</div>
              <h2 className="text-4xl font-bold tracking-tighter uppercase leading-tight">Signal Received<br/>Successfully//</h2>
              <p className="text-white/40 text-sm tracking-widest uppercase font-bold">You are now tuned to the Vibe frequency.</p>
              <button onClick={onClose} className="mt-4 bg-brand-blue text-black px-8 py-3 rounded-full font-bold uppercase text-xs tracking-widest hover:bg-white transition-colors">
                RETURN TO VIBE//
              </button>
            </div>
          ) : (
            <>
              <div className="bg-brand-plum text-black inline-block px-5 py-1 rounded-full text-[10px] font-bold mb-4 uppercase tracking-[0.2em]">
                {status === 'error' ? 'Transmission Failed//' : 'Direct Signal Established//'}
              </div>
              <h2 className="text-4xl md:text-5xl font-bold tracking-tighter leading-tight uppercase">
                Join the<br/><span className="text-brand-straw italic underline decoration-brand-blue underline-offset-8">Vibe House//</span>
              </h2>
              <p className="text-white/40 text-base leading-relaxed font-light max-w-sm mx-auto">
                Stay tuned to the frequency. Get notified about soulful drops and limited archives.
              </p>
              <form onSubmit={handleSubmit} className="space-y-4 pt-6">
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="YOUR_EMAIL@VIBE.COM"
                  required
                  disabled={status === 'submitting'}
                  className="w-full bg-black border-2 border-white/10 rounded-full px-8 py-5 text-white focus:outline-none focus:border-brand-plum transition-all text-center uppercase font-bold text-sm tracking-widest placeholder:text-white/5"
                />
                <button
                  type="submit"
                  disabled={status === 'submitting'}
                  className="w-full bg-brand-blue text-black font-bold py-5 rounded-full hover:bg-white transition-all transform hover:scale-[1.02] text-lg shadow-xl uppercase tracking-tighter"
                >
                  {status === 'submitting' ? 'SENDING...' : 'INITIATE CONNECTION//'}
                </button>
                {status === 'error' && <p className="text-brand-red text-[10px] uppercase font-bold">Error. Signal interference detected.</p>}
                <p className="text-[10px] text-white/20 uppercase tracking-[0.3em] font-bold pt-4 underline underline-offset-4 decoration-white/10">Pure intention. No noise.</p>
              </form>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

